 {"id":"asupersync-l5fx","title":"[Web] Implement Router and Routing System","description":"## Overview\n\nImplement the core routing system for the web framework, providing type-safe, composable route definitions with support for path parameters, method matching, and middleware.\n\n## Implementation Steps\n\n### Step 1: Create Route Matching Types\n\n```rust\n// src/web/router/route.rs\n\nuse std::collections::HashMap;\n\n/// A segment in a route pattern.\n#[derive(Debug, Clone, PartialEq, Eq)]\npub enum RouteSegment {\n    /// Exact match: `/users`\n    Static(String),\n    /// Parameter capture: `/:id`\n    Param(String),\n    /// Wildcard: `/*path` (captures rest)\n    Wildcard(String),\n}\n\n/// Compiled route pattern for efficient matching.\n#[derive(Debug, Clone)]\npub struct RoutePattern {\n    segments: Vec<RouteSegment>,\n    param_names: Vec<String>,\n}\n\nimpl RoutePattern {\n    /// Parse a route pattern string.\n    pub fn parse(pattern: &str) -> Result<Self, RouteError> {\n        let mut segments = Vec::new();\n        let mut param_names = Vec::new();\n\n        for part in pattern.split('/').filter(|s| !s.is_empty()) {\n            let segment = if let Some(name) = part.strip_prefix(':') {\n                if name.is_empty() {\n                    return Err(RouteError::InvalidPattern(\"empty parameter name\".into()));\n                }\n                param_names.push(name.to_string());\n                RouteSegment::Param(name.to_string())\n            } else if let Some(name) = part.strip_prefix('*') {\n                if name.is_empty() {\n                    return Err(RouteError::InvalidPattern(\"empty wildcard name\".into()));\n                }\n                param_names.push(name.to_string());\n                RouteSegment::Wildcard(name.to_string())\n            } else {\n                RouteSegment::Static(part.to_string())\n            };\n            segments.push(segment);\n        }\n\n        Ok(Self { segments, param_names })\n    }\n\n    /// Match a path and extract parameters.\n    pub fn match_path(&self, path: &str) -> Option<PathParams> {\n        let parts: Vec<&str> = path.split('/').filter(|s| !s.is_empty()).collect();\n        let mut params = HashMap::new();\n        let mut part_idx = 0;\n\n        for segment in &self.segments {\n            match segment {\n                RouteSegment::Static(expected) => {\n                    if part_idx >= parts.len() || parts[part_idx] != expected {\n                        return None;\n                    }\n                    part_idx += 1;\n                }\n                RouteSegment::Param(name) => {\n                    if part_idx >= parts.len() {\n                        return None;\n                    }\n                    params.insert(name.clone(), parts[part_idx].to_string());\n                    part_idx += 1;\n                }\n                RouteSegment::Wildcard(name) => {\n                    // Capture all remaining segments\n                    let rest = parts[part_idx..].join(\"/\");\n                    params.insert(name.clone(), rest);\n                    return Some(PathParams(params));\n                }\n            }\n        }\n\n        // Must consume all parts\n        if part_idx == parts.len() {\n            Some(PathParams(params))\n        } else {\n            None\n        }\n    }\n}\n\n/// Extracted path parameters.\n#[derive(Debug, Clone, Default)]\npub struct PathParams(HashMap<String, String>);\n\nimpl PathParams {\n    /// Get a parameter value.\n    pub fn get(&self, name: &str) -> Option<&str> {\n        self.0.get(name).map(|s| s.as_str())\n    }\n\n    /// Parse a parameter as a specific type.\n    pub fn parse<T: std::str::FromStr>(&self, name: &str) -> Option<T> {\n        self.0.get(name).and_then(|s| s.parse().ok())\n    }\n}\n```\n\n### Step 2: Implement Router Core\n\n```rust\n// src/web/router/mod.rs\n\nuse crate::http::{Method, Request, Response};\nuse crate::service::{Service, Layer};\nuse std::future::Future;\nuse std::pin::Pin;\nuse std::sync::Arc;\n\n/// Type-erased handler function.\npub type BoxedHandler = Arc<\n    dyn Fn(Request, PathParams) -> Pin<Box<dyn Future<Output = Response> + Send>> + Send + Sync\n>;\n\n/// A single route entry.\nstruct RouteEntry {\n    pattern: RoutePattern,\n    method: MethodFilter,\n    handler: BoxedHandler,\n}\n\n/// Method filter for routes.\n#[derive(Debug, Clone, Copy)]\npub enum MethodFilter {\n    Any,\n    Specific(Method),\n}\n\nimpl MethodFilter {\n    fn matches(&self, method: &Method) -> bool {\n        match self {\n            MethodFilter::Any => true,\n            MethodFilter::Specific(m) => m == method,\n        }\n    }\n}\n\n/// The main router type.\npub struct Router<S = ()> {\n    routes: Vec<RouteEntry>,\n    fallback: Option<BoxedHandler>,\n    state: S,\n    middleware: Vec<Arc<dyn Layer<BoxedHandler, Service = BoxedHandler> + Send + Sync>>,\n}\n\nimpl Router<()> {\n    /// Create a new router.\n    pub fn new() -> Self {\n        Self {\n            routes: Vec::new(),\n            fallback: None,\n            state: (),\n            middleware: Vec::new(),\n        }\n    }\n}\n\nimpl<S: Clone + Send + Sync + 'static> Router<S> {\n    /// Add state to the router.\n    pub fn with_state<S2>(self, state: S2) -> Router<S2> {\n        Router {\n            routes: self.routes,\n            fallback: self.fallback,\n            state,\n            middleware: self.middleware,\n        }\n    }\n\n    /// Add a route with a specific method.\n    pub fn route<H, T>(mut self, pattern: &str, method: Method, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        let pattern = RoutePattern::parse(pattern)\n            .expect(\"invalid route pattern\");\n\n        let state = self.state.clone();\n        let handler: BoxedHandler = Arc::new(move |req, params| {\n            let handler = handler.clone();\n            let state = state.clone();\n            Box::pin(async move {\n                handler.call(req, params, state).await\n            })\n        });\n\n        self.routes.push(RouteEntry {\n            pattern,\n            method: MethodFilter::Specific(method),\n            handler,\n        });\n        self\n    }\n\n    /// GET route shorthand.\n    pub fn get<H, T>(self, pattern: &str, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        self.route(pattern, Method::GET, handler)\n    }\n\n    /// POST route shorthand.\n    pub fn post<H, T>(self, pattern: &str, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        self.route(pattern, Method::POST, handler)\n    }\n\n    /// PUT route shorthand.\n    pub fn put<H, T>(self, pattern: &str, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        self.route(pattern, Method::PUT, handler)\n    }\n\n    /// DELETE route shorthand.\n    pub fn delete<H, T>(self, pattern: &str, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        self.route(pattern, Method::DELETE, handler)\n    }\n\n    /// Set fallback handler for unmatched routes.\n    pub fn fallback<H, T>(mut self, handler: H) -> Self\n    where\n        H: Handler<T, S> + Send + Sync + 'static,\n        T: 'static,\n    {\n        let state = self.state.clone();\n        self.fallback = Some(Arc::new(move |req, params| {\n            let handler = handler.clone();\n            let state = state.clone();\n            Box::pin(async move {\n                handler.call(req, params, state).await\n            })\n        }));\n        self\n    }\n\n    /// Nest another router under a prefix.\n    pub fn nest(mut self, prefix: &str, other: Router<S>) -> Self {\n        for entry in other.routes {\n            let combined = format!(\"{}{}\", prefix.trim_end_matches('/'),\n                                   format!(\"/{}\", entry.pattern.to_string()).as_str());\n            let pattern = RoutePattern::parse(&combined)\n                .expect(\"invalid nested pattern\");\n            self.routes.push(RouteEntry {\n                pattern,\n                method: entry.method,\n                handler: entry.handler,\n            });\n        }\n        self\n    }\n\n    /// Match a request to a route.\n    pub fn match_route(&self, req: &Request) -> Option<(&BoxedHandler, PathParams)> {\n        for entry in &self.routes {\n            if entry.method.matches(req.method()) {\n                if let Some(params) = entry.pattern.match_path(req.uri().path()) {\n                    return Some((&entry.handler, params));\n                }\n            }\n        }\n        self.fallback.as_ref().map(|h| (h, PathParams::default()))\n    }\n}\n\nimpl<S: Clone + Send + Sync + 'static> Service<Request> for Router<S> {\n    type Response = Response;\n    type Error = Infallible;\n    type Future = Pin<Box<dyn Future<Output = Result<Response, Infallible>> + Send>>;\n\n    fn poll_ready(&mut self, _cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {\n        Poll::Ready(Ok(()))\n    }\n\n    fn call(&mut self, req: Request) -> Self::Future {\n        match self.match_route(&req) {\n            Some((handler, params)) => {\n                let handler = handler.clone();\n                Box::pin(async move {\n                    Ok(handler(req, params).await)\n                })\n            }\n            None => {\n                Box::pin(async {\n                    Ok(Response::builder()\n                        .status(404)\n                        .body(\"Not Found\".into())\n                        .unwrap())\n                })\n            }\n        }\n    }\n}\n```\n\n### Step 3: Implement Handler Trait\n\n```rust\n// src/web/handler.rs\n\nuse crate::http::{Request, Response};\nuse std::future::Future;\n\n/// Trait for request handlers.\npub trait Handler<T, S = ()>: Clone + Send + Sized + 'static {\n    /// The future type returned by the handler.\n    type Future: Future<Output = Response> + Send;\n\n    /// Call the handler.\n    fn call(self, req: Request, params: PathParams, state: S) -> Self::Future;\n}\n\n// Implement Handler for async functions with various argument combinations\n// ... (implementations for 0-12 extractors)\n```\n\n## Cancel-Safety Considerations\n\n- Route matching is synchronous and inherently cancel-safe\n- Handler futures must be cancel-safe; document that handlers should use two-phase patterns for state mutations\n- Router state is immutable during request handling\n- Middleware layers should propagate cancellation correctly\n\n## Unit Tests\n\n```rust\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn pattern_parsing() {\n        let pattern = RoutePattern::parse(\"/users/:id/posts/:post_id\").unwrap();\n        assert_eq!(pattern.segments.len(), 4);\n        assert_eq!(pattern.param_names, vec![\"id\", \"post_id\"]);\n    }\n\n    #[test]\n    fn pattern_matching() {\n        let pattern = RoutePattern::parse(\"/users/:id\").unwrap();\n\n        let params = pattern.match_path(\"/users/123\").unwrap();\n        assert_eq!(params.get(\"id\"), Some(\"123\"));\n\n        assert!(pattern.match_path(\"/users\").is_none());\n        assert!(pattern.match_path(\"/posts/123\").is_none());\n    }\n\n    #[test]\n    fn wildcard_matching() {\n        let pattern = RoutePattern::parse(\"/files/*path\").unwrap();\n\n        let params = pattern.match_path(\"/files/a/b/c.txt\").unwrap();\n        assert_eq!(params.get(\"path\"), Some(\"a/b/c.txt\"));\n    }\n\n    #[tokio::test]\n    async fn router_basic() {\n        let router = Router::new()\n            .get(\"/\", || async { Response::new(\"index\") })\n            .get(\"/users/:id\", |Path(id): Path<u32>| async move {\n                Response::new(format!(\"user {}\", id))\n            });\n\n        let req = Request::get(\"/users/42\").unwrap();\n        let (handler, params) = router.match_route(&req).unwrap();\n        assert_eq!(params.get(\"id\"), Some(\"42\"));\n    }\n\n    #[tokio::test]\n    async fn router_nested() {\n        let api = Router::new()\n            .get(\"/users\", || async { Response::new(\"users list\") });\n\n        let router = Router::new()\n            .nest(\"/api/v1\", api);\n\n        let req = Request::get(\"/api/v1/users\").unwrap();\n        assert!(router.match_route(&req).is_some());\n    }\n}\n```\n\n## E2E Tests\n\n```rust\n#[cfg(test)]\nmod e2e_tests {\n    use super::*;\n    use crate::lab::LabRuntime;\n    use tracing::{info, debug};\n\n    #[test]\n    fn e2e_router_full_lifecycle() {\n        let lab = LabRuntime::builder()\n            .with_tracing(\"web_router=debug\")\n            .build();\n\n        lab.run(async {\n            info!(\"Creating router with multiple routes\");\n\n            let router = Router::new()\n                .get(\"/\", || async {\n                    debug!(\"Handling index request\");\n                    Response::new(\"Welcome\")\n                })\n                .get(\"/users/:id\", |Path(id): Path<u32>| async move {\n                    debug!(user_id = id, \"Handling user detail\");\n                    Response::new(format!(r#\"{{\"id\":{}}}\"#, id))\n                })\n                .fallback(|| async {\n                    Response::builder().status(404).body(\"Not Found\").unwrap()\n                });\n\n            info!(\"Testing route matching\");\n            let req = Request::get(\"/users/42\").unwrap();\n            let resp = router.clone().call(req).await.unwrap();\n            assert_eq!(resp.status(), 200);\n\n            info!(\"E2E router test completed successfully\");\n        });\n    }\n}\n```\n\n## Logging Requirements\n\n- DEBUG: Route pattern compilation, route matching attempts\n- INFO: Router creation, route registration\n- WARN: Overlapping route patterns detected\n- ERROR: Invalid route patterns, handler panics\n\n## Files to Create\n\n- `src/web/mod.rs`\n- `src/web/router/mod.rs`\n- `src/web/router/route.rs`\n- `src/web/handler.rs`\n","status":"closed","priority":1,"issue_type":"task","created_at":"2026-01-17T15:44:42.646425459Z","created_by":"Dicklesworthstone","updated_at":"2026-01-29T05:32:17.909900052Z","closed_at":"2026-01-29T05:32:17.909810606Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"asupersync-l5fx","depends_on_id":"asupersync-4qw","type":"blocks","created_at":"2026-02-13T18:30:39Z","created_by":"import","metadata":"{}","thread_id":""}]}
 {"id":"asupersync-l6l","title":"Implement lab runtime with virtual time and deterministic scheduling","description":"# Lab Runtime with Virtual Time and Deterministic Scheduling\n\n## Purpose\nThe lab runtime is the executable semantics of Asupersync:\n- **virtual time** (discrete ticks)\n- **deterministic scheduling** (seeded, reproducible)\n- **trace capture + replay**\n\nThis is what makes concurrency bugs reproducible artifacts instead of “heisenbugs”.\n\n## Key Guarantees\nGiven the same lab config (including seed) and the same user program:\n- the runtime produces the same observable trace\n- replay can reproduce a failing run\n\n## Core Constraints\n- Avoid ambient globals.\n- Avoid OS entropy / wall-clock time for scheduling decisions.\n- Prefer minimal dependencies; implement deterministic PRNG internally (see bead: deterministic PRNG utility).\n\n## LabRuntime Structure\n\n```rust\npub struct LabRuntime {\n    state: RuntimeState,\n    virtual_time: Time,\n\n    /// Deterministic PRNG for tie-breaking (no rand crate).\n    rng: DetRng,\n\n    trace: TraceBuffer,\n    config: LabConfig,\n}\n\npub struct LabConfig {\n    pub seed: u64,\n    pub max_time: Option<Time>,\n    pub max_steps: Option<u64>,\n\n    /// Lab-only strictness knobs.\n    pub panic_on_leak: bool,\n    pub panic_on_invariant_violation: bool,\n}\n```\n\n## Virtual Time\nTime advances only when no runnable tasks exist.\n\nAlgorithm:\n1. If scheduler has runnable tasks: do not advance time.\n2. Otherwise, jump to next timer deadline (if any).\n3. Wake any tasks whose timers expire.\n4. Check deadline expiries and request cancellation as needed.\n5. Emit `TraceEvent::Tick`.\n\nThis yields the “sleeps are instant in wall-clock time” property while preserving a meaningful virtual timeline.\n\n## Deterministic Scheduling\nWhen multiple tasks are eligible to run, break ties deterministically using `DetRng` seeded by `LabConfig.seed`.\n\nImportant: determinism requires that tie-breaking inputs are stable.\n- do not iterate hashmaps/sets and rely on their order\n- prefer ordered iteration or explicit sorting by IDs\n\n## Main Loop (Sketch)\n\n```rust\nloop {\n    if should_stop_by_limits(config, virtual_time, steps) {\n        break;\n    }\n\n    if let Some(task_id) = scheduler.pick_next(virtual_time, &mut rng, &state) {\n        poll_task(task_id);\n        steps += 1;\n        verify_invariants_if_enabled();\n    } else {\n        tick_virtual_time();\n    }\n}\n```\n\n## Trace Capture\nEvery semantic operation emits a trace event. The trace model should stay small and semantic:\n- spawn/complete\n- cancel/propagate\n- reserve/commit/abort/leak\n- finalize/close\n- tick\n\nThe trace is the primary debugging artifact for test failures.\n\n## Replay\nReplay means: “run again under the same seed/config and ensure we reproduce the same trace”.\n\nMinimum viable replay:\n- re-run the scenario under the same seed\n- compare traces\n- report first divergence with context\n\n(Phase 5 adds canonicalization and equivalence-class reasoning; Phase 0 replay can be strict byte-for-byte equality.)\n\n## Acceptance Criteria\n1. Same seed/config yields identical traces for the same program.\n2. Virtual time advances only when nothing runnable exists.\n3. Trace capture is complete enough for invariants/oracles.\n4. Replay reports divergence precisely.\n\n## Testing Requirements\n- Determinism oracle runs at least 3 scenarios twice and asserts trace equality.\n- Deadlock/idle detection is explicit and traceable.\n\n","status":"tombstone","priority":0,"issue_type":"task","created_at":"2026-01-16T06:30:26.261310057Z","created_by":"Dicklesworthstone","updated_at":"2026-02-06T02:44:22.849363887Z","closed_at":"2026-02-06T02:44:22.849363887Z","close_reason":"Lab runtime implemented in src/lab/runtime.rs. Virtual time, DetRng for determinism, trace capture, quiescence checking. Config in config.rs, replay/diff in replay.rs.","source_repo":".","deleted_at":"2026-02-06T02:44:22.849349530Z","deleted_by":"system","delete_reason":"merge deletion","original_type":"task","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"asupersync-l6l","depends_on_id":"asupersync-4sm","type":"blocks","created_at":"2026-02-13T18:30:44Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"asupersync-l6l","depends_on_id":"asupersync-845","type":"blocks","created_at":"2026-02-13T18:30:44Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"asupersync-l6l","depends_on_id":"asupersync-akx.1.1","type":"blocks","created_at":"2026-02-13T18:30:44Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"asupersync-l6l","depends_on_id":"asupersync-tgl","type":"blocks","created_at":"2026-02-13T18:30:44Z","created_by":"import","metadata":"{}","thread_id":""}]}
 {"id":"asupersync-l6lfx","title":"net_udp tests require test-internals feature but net_tcp doesn't","description":"The UDP tests in tests/net_udp.rs have #![cfg(feature = \"test-internals\")] at line 2, but the TCP tests in tests/net_tcp.rs don't have this requirement. This causes UDP tests to be skipped during normal cargo test runs.\n\nEither:\n1. Remove the feature flag from net_udp.rs if it's not needed\n2. Add the feature flag to net_tcp.rs and net_unix.rs for consistency\n3. Document why UDP tests require the feature flag\n\nCurrent behavior:\n- cargo test --test net_udp → 0 tests run\n- cargo test --test net_udp --features test-internals → 14 tests run\n- cargo test --test net_tcp → 15 tests run (no feature needed)","status":"closed","priority":3,"issue_type":"bug","created_at":"2026-01-26T06:19:48.761570411Z","created_by":"ubuntu","updated_at":"2026-01-26T06:28:06.278588015Z","closed_at":"2026-01-26T06:28:06.278528513Z","close_reason":"Fixed: Removed unnecessary test-internals feature flag from net_udp.rs","source_repo":".","compaction_level":0,"original_size":0}
